s4-code-busqueda.code:
lecturas = [21.0, 22.5, 95.0, 23.0]  # grados C
limite = 80
posicion_falla = -1

for i in range(len(lecturas)):
    if lecturas[i] > limite:
        posicion_falla = i
        break  # no hace falta seguir buscando

if posicion_falla == -1:
    print("Sin fallas en el lote")
else:
    print(f"Primera falla en posicion {posicion_falla}: {lecturas[posicion_falla]} C")

