temperaturas = [21.0, -5.0, 45.0, -2.0, 130.0, 30.0]
validas = 0
for t in temperaturas:
    if t < 0:
        continue          # error de sensor: se ignora
    if t > 100:
        break             # falla critica: se detiene
    validas += 1
print(f"Lecturas validas procesadas: {validas}")

matriz = [[12, 88, 40], [95, 30, 70], [60, 99, 20]]
